/**
 * Helper class for Min Priority Queue
 * Stores elements as [priority1, priority2, data...]
 * Priority is based on comparison logic provided.
 */
class PriorityQueue {
    constructor(comparator = (a, b) => a[0] - b[0]) {
        this._heap = [];
        this._comparator = comparator;
    }

    size() {
        return this._heap.length;
    }

    isEmpty() {
        return this.size() === 0;
    }

    peek() {
        return this._heap[0];
    }

    push(item) {
        this._heap.push(item);
        this._bubbleUp(this.size() - 1);
    }

    pop() {
        if (this.isEmpty()) return undefined;
        const top = this._heap[0];
        const last = this._heap.pop();
        if (!this.isEmpty()) {
            this._heap[0] = last;
            this._bubbleDown(0);
        }
        return top;
    }

    _bubbleUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this._comparator(this._heap[index], this._heap[parentIndex]) < 0) {
                [this._heap[index], this._heap[parentIndex]] = [this._heap[parentIndex], this._heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    _bubbleDown(index) {
        const lastIndex = this.size() - 1;
        while (true) {
            let leftChildIndex = 2 * index + 1;
            let rightChildIndex = 2 * index + 2;
            let smallest = index;

            // Compare with left child
            if (leftChildIndex <= lastIndex && this._comparator(this._heap[leftChildIndex], this._heap[smallest]) < 0) {
                smallest = leftChildIndex;
            }

            // Compare with right child
            if (rightChildIndex <= lastIndex && this._comparator(this._heap[rightChildIndex], this._heap[smallest]) < 0) {
                smallest = rightChildIndex;
            }

            if (smallest !== index) {
                [this._heap[index], this._heap[smallest]] = [this._heap[smallest], this._heap[index]];
                index = smallest;
            } else {
                break;
            }
        }
    }
}


function solve(n, m, sources) {
    // Dimensions
    const R = n;
    const C = m;

    // Initialize distance array (Time) to Infinity
    const dist = Array(R).fill(0).map(() => Array(C).fill(Infinity));
    // Initialize color grid to 0 (uncolored)
    const finalGrid = Array(R).fill(0).map(() => Array(C).fill(0));

    // Priority Queue setup for Dijkstra.
    // State in PQ: [Time, NegativeColor, Row, Col]
    // Comparator prioritizes:
    // 1. Minimum Time (Time - Time')
    // 2. Maximum Color (NegativeColor - NegativeColor', which means minimizing NegativeColor, i.e., maximizing Color)
    const pq = new PriorityQueue((a, b) => {
        // a[0] is Time, a[1] is NegativeColor
        if (a[0] !== b[0]) {
            return a[0] - b[0]; // Min Time
        }
        return a[1] - b[1]; // Min NegativeColor (Max Color)
    });

    // Initialize sources
    for (const source of sources) {
        const [r, c, color] = source;

        // Handle initialization if multiple sources start at the same spot (though constraints say they are unique)
        if (dist[r][c] > 0) {
            dist[r][c] = 0;
            finalGrid[r][c] = color;
            // Push [Time=0, NegativeColor=-color, R, C]
            pq.push([0, -color, r, c]);
        }
    }

    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    while (!pq.isEmpty()) {
        const [timeCurr, negColorCurr, r, c] = pq.pop();
        const colorCurr = -negColorCurr;

        // Stale check: If we found a faster path already, ignore this entry.
        // Note: If timeCurr == dist[r][c], we might still process it if the color was improved previously, 
        // but the logic below handles that by only relaxing/re-pushing if improvement occurs.
        if (timeCurr > dist[r][c]) {
            continue;
        }

        // If timeCurr == dist[r][c] but colorCurr is less than finalGrid[r][c], ignore it.
        // This check is technically redundant if the relaxation logic is perfect, but provides safety against stale color updates.
        if (timeCurr === dist[r][c] && colorCurr < finalGrid[r][c]) {
             continue;
        }


        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            // Check boundaries
            if (nr >= 0 && nr < R && nc >= 0 && nc < C) {
                const timeNew = timeCurr + 1;

                // Case 1: Found a strictly faster path
                if (timeNew < dist[nr][nc]) {
                    dist[nr][nc] = timeNew;
                    finalGrid[nr][nc] = colorCurr;
                    pq.push([timeNew, -colorCurr, nr, nc]);
                } 
                // Case 2: Tie in arrival time
                else if (timeNew === dist[nr][nc]) {
                    // Check for better color in case of time tie
                    if (colorCurr > finalGrid[nr][nc]) {
                        finalGrid[nr][nc] = colorCurr;
                        // Since the color improved at the minimum time, we must re-push this state
                        // to propagate the better color outwards.
                        pq.push([timeNew, -colorCurr, nr, nc]);
                    }
                }
                // Case 3: Slower path, do nothing.
            }
        }
    }

    return finalGrid;
}

